glsl.vertex:
varying vec2 vUv;
void main(){
 vUv=uv;
 gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float time;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453123);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);vec2 u=f*f*(3.0-2.0*f);return mix(mix(hash(i),hash(i+vec2(1.0,0.0)),u.x),mix(hash(i+vec2(0.0,1.0)),hash(i+vec2(1.0,1.0)),u.x),u.y);}
void main(){
 vec2 uv=vUv;
 vec3 ochre=vec3(0.788,0.584,0.314);
 vec3 rose=vec3(0.716,0.416,0.333);
 vec3 straw=vec3(0.858,0.704,0.427);
 float n=noise(uv*115.0)+0.5*noise(uv*37.0+4.0);
 float wash=smoothstep(0.15,0.95,noise(uv*5.5));
 vec3 col=mix(ochre,rose,0.16*wash);
 col=mix(col,straw,0.12*n);
 float edge=distance(uv,vec2(0.5));
 col*=1.0-0.12*smoothstep(0.48,0.74,edge);
 col+=0.035*(n-0.5);
 gl_FragColor=vec4(col,1.0);
}

precision mediump float;
varying vec2 vUv;
float sdTri(vec2 p, vec2 a, vec2 b, vec2 c){
 vec2 e0=b-a,e1=c-b,e2=a-c;
 vec2 v0=p-a,v1=p-b,v2=p-c;
 vec2 pq0=v0-e0*clamp(dot(v0,e0)/dot(e0,e0),0.0,1.0);
 vec2 pq1=v1-e1*clamp(dot(v1,e1)/dot(e1,e1),0.0,1.0);
 vec2 pq2=v2-e2*clamp(dot(v2,e2)/dot(e2,e2),0.0,1.0);
 float s=sign(e0.x*e2.y-e0.y*e2.x);
 vec2 d=min(min(vec2(dot(pq0,pq0),s*(v0.x*e0.y-v0.y*e0.x)),vec2(dot(pq1,pq1),s*(v1.x*e1.y-v1.y*e1.x))),vec2(dot(pq2,pq2),s*(v2.x*e2.y-v2.y*e2.x)));
 return -sqrt(d.x)*sign(d.y);
}
float hash(vec2 p){return fract(sin(dot(p,vec2(41.0,289.0)))*9157.13);}
void main(){
 vec2 uv=vUv;
 float top=sdTri(uv,vec2(0.18,0.78),vec2(0.82,0.78),vec2(0.5,0.33));
 float bot=sdTri(uv,vec2(0.18,0.25),vec2(0.82,0.25),vec2(0.5,0.69));
 float topFill=smoothstep(0.018,-0.012,top);
 float botFill=smoothstep(0.018,-0.012,bot);
 float topEdge=smoothstep(0.018,0.0,abs(top))-smoothstep(0.012,0.004,abs(top));
 float botEdge=smoothstep(0.018,0.0,abs(bot))-smoothstep(0.012,0.004,abs(bot));
 float grain=hash(floor(uv*170.0));
 vec3 red=vec3(0.784,0.247,0.149);
 vec3 orange=vec3(0.910,0.541,0.180);
 vec3 gold=vec3(0.847,0.678,0.286);
 vec3 col=red*topFill+orange*botFill;
 float a=max(topFill*0.78,botFill*0.72);
 col=mix(col,col+vec3(0.05,0.025,0.0)*(grain-0.5),0.65);
 float edge=max(topEdge,botEdge);
 col=mix(col,gold,edge);
 a=max(a,edge*0.95);
 gl_FragColor=vec4(col,a);
}

precision mediump float;
varying vec2 vUv;
void main(){
 vec2 uv=vUv;
 float x=abs(uv.x-0.5);
 float line=smoothstep(0.012,0.004,x);
 float gap=1.0-smoothstep(0.044,0.052,abs(uv.y-0.61));
 float topMask=smoothstep(0.18,0.23,uv.y)*(1.0-smoothstep(0.84,0.9,uv.y));
 float a=line*topMask*(1.0-gap);
 float crisp=line*smoothstep(0.054,0.07,abs(uv.y-0.61));
 vec3 gold=vec3(0.86,0.68,0.26);
 vec3 darkGold=vec3(0.52,0.34,0.10);
 vec3 col=mix(darkGold,gold,crisp);
 gl_FragColor=vec4(col,a*0.96);
}

precision mediump float;
varying vec2 vUv;
void main(){
 vec2 uv=vUv;
 vec2 c=vec2(0.5,0.43);
 vec2 p=uv-c;
 p.x*=1.08;
 float d=length(p);
 float disc=smoothstep(0.056,0.048,d);
 float r1=1.0-smoothstep(0.004,0.008,abs(d-0.068));
 float r2=1.0-smoothstep(0.003,0.006,abs(d-0.083));
 vec3 blue=vec3(0.149,0.271,0.373);
 vec3 blueLit=vec3(0.22,0.37,0.48);
 vec3 gold=vec3(0.86,0.68,0.28);
 vec3 col=mix(blue,blueLit,smoothstep(0.052,0.0,d));
 float ring=max(r1*0.82,r2*0.62);
 col=mix(col,gold,ring);
 float a=max(disc*0.9,ring);
 gl_FragColor=vec4(col,a);
}

precision mediump float;
varying vec2 vUv;
float seg(vec2 p, vec2 a, vec2 b){vec2 pa=p-a,ba=b-a;float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0);return length(pa-ba*h);}
void main(){
 vec2 uv=vUv;
 float m=0.0;
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.42,0.66),vec2(0.47,0.61))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.53,0.67),vec2(0.59,0.62))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.39,0.58),vec2(0.45,0.56))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.56,0.57),vec2(0.64,0.54))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.47,0.72),vec2(0.51,0.68))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.52,0.51),vec2(0.49,0.47))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.34,0.63),vec2(0.38,0.60))));
 m=max(m,1.0-smoothstep(0.002,0.006,seg(uv,vec2(0.62,0.70),vec2(0.67,0.66))));
 vec3 ink=vec3(0.35,0.12,0.07);
 gl_FragColor=vec4(ink,m*0.46);
}
